  ('heelevel3-d0d1b9a2-moex-00030', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-114-ac2adf20', 'sub-heelevel3-d0d1b9a2-02', NULL, 'single_choice', '依政府會計準則公報第6號規定，甲機關於X7年1月1日以融資租賃向A公司租用辦公設備 一部，租期4年，每年1月1日給付租金15萬元，租期屆滿時該設備之估計殘值7萬元，甲機 關得以 2萬元之價格承購，該設備於 X7年 1月1日之公允價格為 59.125萬元，有效利率 3% （利率3%，4期之複利現值=0.888；利率3%，3期之年金現值=2.829），甲機關於X7年1月1 日取得該設備時應認列之應付租賃款為：', '["59.211萬元", "59.125萬元", "57.435萬元", "57.125萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:57+00:00", "source_pdf_sha1": "f94e541413bf", "answer_pdf_sha1": "1d17bc81324b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "225", "s": "0808", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
